import java.io.*;

// Writing to a file with FileOutputStream
// A block where exceptions may occur
try (FileOutputStream fos = new FileOutputStream("output.dat")) {
    fos.write(65);  // ASCII code for 'A'
    fos.write(66);  // 'B'
    byte[] data = {67, 68, 69}; // C, D, E
    fos.write(data);
} // close() is called automatically

// Reading from a file with FileInputStream
// A block where exceptions may occur
try (FileInputStream fis = new FileInputStream("output.dat")) {
    int b;
    // Repeat while the condition is true
    while ((b = fis.read()) != -1) {
        System.out.print((char) b); // ABCDE
    }
}

// Efficient reading with buffering
// A block where exceptions may occur
try (BufferedInputStream bis = new BufferedInputStream(
        new FileInputStream("output.dat"))) {
    byte[] buffer = new byte[1024];
    // Variable declaration and initialization
    int len = bis.read(buffer);
    System.out.println(new String(buffer, 0, len)); // ABCDE
}

