import java.io.*;

// Basic try-with-resources
// A block where exceptions may occur
try (FileReader fr = new FileReader("input.txt");
     BufferedReader br = new BufferedReader(fr)) {
    System.out.println(br.readLine());
} // close() is called in order: br → fr

// Java 9+: Using pre-declared variables
FileReader fr = new FileReader("input.txt");
BufferedReader br = new BufferedReader(fr);
// A block where exceptions may occur
try (br) {  // Effectively final variable
    System.out.println(br.readLine());
}

// catch/finally can also be used
// A block where exceptions may occur
try (FileWriter fw = new FileWriter("log.txt")) {
    fw.write("LogMessage");
} catch (IOException e) {
    System.err.println("WriteError: " + e.getMessage());
} finally {
    System.out.println("Processing complete");
}

