import java.nio.file.*;
import java.io.File;

// Creating a Path with Paths.get()
Path p1 = Paths.get("/home/user/docs/file.txt");
Path p2 = Paths.get("/home", "user", "docs", "file.txt");

// Creating a Path with Path.of() (Java 11+)
Path p3 = Path.of("/home/user/docs/file.txt");
Path p4 = Path.of("/home", "user", "docs");

// Converting between File and Path
File file = p1.toFile();
Path p5 = file.toPath();

// Relative path
Path relative = Path.of("src", "main", "App.java");
System.out.println(relative); // src/main/App.java

import java.nio.file.*;

// resolve: Joining paths
Path base = Path.of("/home/user");
System.out.println(base.resolve("docs/file.txt"));
// → /home/user/docs/file.txt

// Resolving with an absolute path returns the argument as-is
System.out.println(base.resolve("/etc/config"));
// → /etc/config

// relativize: Computing a relative path
Path p1 = Path.of("/home/user/docs");
Path p2 = Path.of("/home/user/pics/photo.jpg");
System.out.println(p1.relativize(p2));
// → ../pics/photo.jpg

// normalize: Removing redundant elements
Path p3 = Path.of("/home/user/../user/./docs/file.txt");
System.out.println(p3.normalize());
// → /home/user/docs/file.txt

import java.nio.file.*;

Path p = Path.of("/home/user/docs/file.txt");

System.out.println(p.getFileName());   // file.txt
System.out.println(p.getParent());     // /home/user/docs
System.out.println(p.getRoot());       // /
System.out.println(p.getNameCount());  // 4 (home, user, docs, file.txt)
System.out.println(p.getName(0));      // home
System.out.println(p.getName(3));      // file.txt
System.out.println(p.subpath(1, 3));   // user/docs
System.out.println(p.toAbsolutePath());
// → /home/user/docs/file.txt (already absolute)

// For a relative path
Path rel = Path.of("src/App.java");
System.out.println(rel.getRoot());     // null
System.out.println(rel.toAbsolutePath());
// → current directory/src/App.java

