import java.nio.file.*;

Path source = Path.of("original.txt");
Path target = Path.of("copy.txt");

// Copy (throws exception if target exists)
Files.copy(source, target);

// Overwrite copy
Files.copy(source, target,
    StandardCopyOption.REPLACE_EXISTING);

// Move (rename)
Path moved = Path.of("renamed.txt");
Files.move(target, moved,
    StandardCopyOption.REPLACE_EXISTING);

// Atomic move
Files.move(source, target,
    StandardCopyOption.ATOMIC_MOVE);

// Delete
Files.delete(moved);           // Throws exception if not exists
Files.deleteIfExists(moved);   // OK even if not exists (returns false)

